    "code": "// =============================================================================\r\n// Brittney Agent Station\r\n// =============================================================================\r\n// Customer Service Specialist\r\n// =============================================================================\r\n\r\n@include \"../_lib/components/agent-station.hs\" {\r\n  agent: \"brittney\"\r\n  position_angle: 0\r\n  color: \"#FF69B4\"\r\n  radius: 8\r\n  model: \"crash_couch_tactical\"\r\n  data_source: \"/api/agents/brittney/status\"\r\n  show_avatar: true\r\n  show_tasks: true\r\n  show_metrics: true\r\n\r\n  // Brittney-specific extensions\r\n  extensions {\r\n    // Battlespace seat recline\r\n    seat_config: {\r\n      harness: true,\r\n      recline: \"data.state.isBattlespace ? 45 : 0\"\r\n    }\r\n\r\n    // Customer interaction map (unique to Brittney)\r\n    customer_map {\r\n      position: [0, -0.7, 0]\r\n      type: 3d_network\r\n      size: 0.5\r\n      nodes: customers\r\n      edges: interactions\r\n      color_by: sentiment\r\n      colors: { positive: \"#00ff00\", neutral: \"#ffff00\", negative: \"#ff0000\" }\r\n    }\r\n\r\n    // Avatar appearance customization\r\n    avatar_appearance {\r\n      hair: { color: \"light-pink\", style: \"shoulder-wavy\" }\r\n      eyes: { color: \"hazel-green\", size: \"large\" }\r\n      clothing: \"distressed-jeans-leather-jacket\"\r\n      tattoos: { arms: \"full-sleeve\", chest: \"phoenix\" }\r\n      accessories: { necklace: \"butterfly-pendant\", earrings: \"dangling\", wristbands: true }\r\n      aura_pattern: \"sparkles\"\r\n    }\r\n\r\n    // Embedded React UI for complex intake forms\r\n    ui_panel {\r\n      position: [0, 1.5, 0.5]\r\n      size: [1.5, 1]\r\n      screen: { type: embedded_react, url: \"/agents/brittney/intake\", interactive: true }\r\n      label: { text: \"Customer Intake\", color: \"#FF69B4\" }\r\n    }\r\n  }\r\n}\r\n",
    "description": "Auto-ported template from spaceship-stations-brittney"
